// Extract error details from the error trigger
const errorData = $input.first().json;

const workflowName = errorData.workflow?.name || 'Unknown Workflow';
const workflowId = errorData.workflow?.id || 'unknown';
const errorMessage = errorData.execution?.error?.message || 'Unknown error';
const errorNode = errorData.execution?.error?.node?.name || 'Unknown node';
const executionId = errorData.execution?.id || 'unknown';
const timestamp = new Date().toLocaleString('en-US', {
  timeZone: 'America/New_York',
  dateStyle: 'medium',
  timeStyle: 'medium'
});

return [{
  json: {
    workflow_name: workflowName,
    workflow_id: workflowId,
    error_message: errorMessage,
    error_node: errorNode,
    execution_id: executionId,
    timestamp_est: timestamp,
    source: 'n8n',
    error_type: 'workflow_execution_error',
    stack_trace: errorData.execution?.error?.stack || ''
  }
}];

